content.content:
// Footer dividido: izquierda y derecha
ogComponent('modal').open(resource, {
  title: 'Confirmación',
  footerLeft: '<button class="btn btn-outline-danger">🗑 Eliminar</button>',
  footerRight: '<button class="btn btn-secondary" onclick="ogComponent(\'modal\').closeAll()">Cancelar</button><button class="btn btn-primary">Guardar</button>'
});

// Default: cierra con overlay + ESC + X
ogComponent('modal').open(resource, { title: 'Default' });

// Solo ESC y X (no cierra con clic en overlay)
ogComponent('modal').open(resource, {
  title: 'Solo ESC',
  closeOnOverlay: false
});

// Solo con el botón X
ogComponent('modal').open(resource, {
  title: 'Solo X',
  closeOnOverlay: false,
  closeOnEsc: false
});

// headerExtra: texto/HTML pequeño bajo el título
ogComponent('modal').open(resource, {
  title: 'Detalles del usuario',
  headerExtra: '🟢 Activo · Administrador'
});

// Al abrir el modal de edición, pasa el nombre del registro
static async openEdit(id) {
  const data = await this.get(id);
  if (!data) return;

  ogComponent('modal').open('miext|forms/mi-form', {
    title: 'Editar workflow',
    headerExtra: `✏️ ${data.name} <span style="opacity:.5">#${data.id}</span>`,
    width: '700px',
    afterRender: (formId) => {
      ogModule('form').fill(formId, data);
    }
  });
}

// También puedes actualizar el título de un modal ya abierto:
ogModal.updateTitle(modalId, 'Nuevo título', 'subtexto extra');

// Solo icono antes del título
ogComponent('modal').open(resource, {
  title: 'Configuración OAuth',
  beforeTitle: '🔐'
});

// Badge de estado después del título
ogComponent('modal').open(resource, {
  title: 'Base de datos',
  afterTitle: '<span class=\'badge-pill\'>● Conectada</span>'
});

// Combinado: before + after + extra (sub-línea bajo el título)
ogComponent('modal').open(resource, {
  title: 'Canal WhatsApp',
  beforeTitle: '💬',
  afterTitle: '<span class=\'badge-pill\'>3 pendientes</span>',
  headerExtra: 'API v2 · Webhook activo'
});

// Actualizar before/after en un modal ya abierto:
ogModal.updateTitle(modalId, 'Nuevo título', 'extra', '🟢', 'nuevo after');
